class Solution {
    public boolean equalFrequency(String word) {
        for (int i = 0; i < word.length(); i++) {
            String newWord = word.substring(0, i) + word.substring(i + 1);
            int[] count = new int[26];
            for (char c : newWord.toCharArray()) {
                count[c - 'a']++;
            }
            int uniqueCount = 0;
            int expectedCount = -1;
            for (int j = 0; j < 26; j++) {
                if (count[j] > 0) {
                    if (uniqueCount == 0) {
                        uniqueCount++;
                        expectedCount = count[j];
                    } else if (count[j] != expectedCount) {
                        break;
                    }
                }
                if (j == 25) return true;
            }
        }
        return false;
    }
}
